input.command:
# Check cluster settings for transform-related capacity settings
kubectl -n elasticsearch exec curl-test -- curl -sk -u elastic:elasticpass 'https://es-http:9200/_cluster/settings?pretty&include_defaults=true' 2>/dev/null | python3 -c "
import sys, json
data = json.load(sys.stdin)
# Filter for transform-related settings
for section in ['persistent', 'transient', 'defaults']:
    if section in data:
        for k, v in data[section].items():
            if 'transform' in k.lower():
                print(f'{section}.{k} = {v}')
" 2>/dev/null

